    "id": "GRP0182",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Close your eyes. Build me the night. Where do you go, who's there, what does it feel like when it's exactly right?",
