    "id": "GRP0185",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Something moved that shouldn't have. The air shifted. Tell me about the moment you felt something that had no explanation.",
