    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "You woke up somewhere you didn't lie down. Or someone told you what you'd done. Tell me about the time you walked in your sleep.",
