    "id": "GRP0188",
    "chapter": "playful",
    "role": "build",
    "type": "directed",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "You wanted them to feel it — really feel it. Tell me about the most romantic thing you've ever done for someone.",
