    "id": "GRP0189",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "First love leaves a mark that doesn't fully fade. Tell me who they were and what made them different from everyone before or after.",
