    "id": "GRP0190",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "You didn't mean to fall that fast. But you did. Tell me about the time love caught you completely off guard.",
