    "id": "GRP0191",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "No deflection, no joke. Name one thing you genuinely love about yourself — and say it like you mean it.",
