    "id": "GRP0194",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Strip everything else away. Tell me the one thing a relationship absolutely must have for you to stay.",
