    "id": "GRP0196",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "One look. That was all it took. Tell me about the moment you fell for someone the instant you saw them.",
