    "id": "GRP0197",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "You knew them well enough to get it exactly right. Tell me about the most thoughtful gift you've ever given a partner.",
