    "id": "GRP0199",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Relationships make people brave, or reckless, or both. Tell me the wildest thing you've ever done while you were with someone.",
