    "id": "GRP0200",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "There's something you've thought about. Imagined. Never done. Tell me the naughty thing you've craved but always stopped short of trying.",
