    "id": "GRP0207",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Work and desire crossed paths. Admit what happened — even the version you've tidied up in your memory.",
