    "id": "GRP0211",
    "chapter": "playful",
    "role": "build",
    "type": "group",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "{player}, you are the waiter now. Take everyone's order with charm, flair, and a completely unnecessary accent.",
