    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "You are a cat. Two full minutes. Stretch, prowl, ignore everyone. Commit to it completely — Lyra will know if you don't.",
