    "id": "GRP0215",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Channel a movie character you love. Give us their voice, their posture, their whole presence. Make the room believe you.",
