    "id": "GRP0216",
    "chapter": "playful",
    "role": "build",
    "type": "self",
    "promptType": "truth",
    "intensity": 2.4,
    "text": "Strike your fiercest model pose. Hold it for five full seconds. Chin up. Eyes forward. Do not smile.",
